/*----------------------------------OGGETTO MODELLI 3D, GEOMETRIE E MATERIALI--------------------------------*/
//#region
//FUNZIONE DI MODIFICA MATERIALI
function ConvertMaterialStandardToLucid(Num, Texture, Shininess = 30) {
    Materiali[Num].Type = "Lucido";
    Materiali[Num].Shininess = Shininess;
    Materiali[Num].Specular = Colors.SpecularColor;
    Materiali[Num].RoughMap = false;
    if (Texture == false) {
        Materiali[Num].Map = false;
        Materiali[Num].NormalMap = false;
    };
};
function NoTexture(Num, Map = false) {
    Materiali[Num].Map = Map;
    Materiali[Num].NormalMap = false;
};
export function EditGraphic() {
    //0 CONVERSIONE MATERIALI STANDARD IN LUCIDI, SENZA TEXTURE, NO SHADER
    if (Texture == 0) {
        ConvertMaterialStandardToLucid(0, false);
        ConvertMaterialStandardToLucid(1, false);
        ConvertMaterialStandardToLucid(9, false);
        ConvertMaterialStandardToLucid(11, false);
        ConvertMaterialStandardToLucid(12, false);
        ConvertMaterialStandardToLucid(13, false);
        ConvertMaterialStandardToLucid(14, false);
        ConvertMaterialStandardToLucid(16, false);
        ConvertMaterialStandardToLucid(33, false, 0);
        ConvertMaterialStandardToLucid(34, false);
        ConvertMaterialStandardToLucid(35, false);
        ConvertMaterialStandardToLucid(36, false);
        ConvertMaterialStandardToLucid(37, false);
        ConvertMaterialStandardToLucid(38, false);
        ConvertMaterialStandardToLucid(39, false);
        ConvertMaterialStandardToLucid(40, false);
        ConvertMaterialStandardToLucid(44, false);
        NoTexture(10);
        NoTexture(19, true);                                      //MATERIALE PAVIMENTO HANGAR, TEXTURE COLORE E NORMALE, LUCIDO, FRONT SIDE
        NoTexture(20, true);                                         //MATERIALE PARETI HANGAR, TEXTURE COLORE E NORMALE, LUCIDO, FRONT SIDE
        NoTexture(22, true);
        NoTexture(30);
        Materiali[10].Color = 0x134078;
        Materiali[11].Color = 0xffffff;
        Materiali[14].Color = 0x262a31;
        Materiali[33].Color = 0x000000;
        Materiali[34].Color = 0x707070;
        Materiali[35].Color = 0x4d4b4a;
        Materiali[36].Color = 0x1f2404;
        Materiali[38].Color = 0x727272;
        Materiali[39].Color = 0x5a251f;
    };
    //1 CONVERSIONE MATERIALI STANDARD IN LUCIDI, NO SHADER
    if (Texture == 1) {
        ConvertMaterialStandardToLucid(0, true);
        ConvertMaterialStandardToLucid(1, true);
        ConvertMaterialStandardToLucid(9, true);
        ConvertMaterialStandardToLucid(11, true);
        ConvertMaterialStandardToLucid(12, true);
        ConvertMaterialStandardToLucid(13, true);
        ConvertMaterialStandardToLucid(14, true);
        ConvertMaterialStandardToLucid(16, true);
        ConvertMaterialStandardToLucid(33, true);
        ConvertMaterialStandardToLucid(34, true);
        ConvertMaterialStandardToLucid(35, true);
        ConvertMaterialStandardToLucid(36, true);
        ConvertMaterialStandardToLucid(37, true);
        ConvertMaterialStandardToLucid(38, true);
        ConvertMaterialStandardToLucid(39, true);
        ConvertMaterialStandardToLucid(40, true);
        ConvertMaterialStandardToLucid(44, true);
    };
    //ESCLUSIONE DEL BAGLIORE DEI PIANETI E DEL SOLE
    if (Glow == 0) {
        Oggetti.PlanetarySystem.Glow = false;
        Oggetti.PlanetarySystem.Sun.GlowColor = null;
    };
    //ANTIALIASING
    if (Antialiasing == 0) {
        GameParam.Renderer.Antialias = false;
    };
    if (Antialiasing == 1) {
        GameParam.Renderer.Antialias = true;
    };
    //ESCLUSIONE DELLA MAPPA AMBIENTALE
    if (AmbMap == 0) {
        GameParam.Renderer.AmbientMap.Enable = false;
        HomeParam.Renderer.AmbientMap.Enable = false;
    };
    if (AmbMap == 1) {
        GameParam.Renderer.AmbientMap.Enable = true;
        HomeParam.Renderer.AmbientMap.Enable = true;
    };
};

//AUTOMAZIONE PER MODIFICARE IL MODELLO WORMHOLE DELLA STORIA
const StoryModelObj = {
    FlagMissione: Number(SaveSystem.getItem('FlagMissione')),
    Capitolo: Number(SaveSystem.getItem(`Capitolo`)),
    Missione: Number(SaveSystem.getItem(`Missione`)),
    DeuterioTotal: Number(SaveSystem.getItem(`DeuterioTotal`)),
    TrizioTotal: Number(SaveSystem.getItem(`TrizioTotal`)),
    SoleTotal: Number(SaveSystem.getItem(`SoleTotal`)),

    CalcStep: function () {         //NUMERO DI SEZIONI CIRCOLARI COMPLETATE (MAX 52)
        let Result = 0;
        if (this.Capitolo == 1) {
            if (this.Missione == 0) Result = 1;
            if (this.Missione == 1 || this.Missione == 2) Result = 12;
            if (this.Missione == 3 || this.Missione == 4) Result = 22;
            if (this.Missione == 5 || this.Missione == 6) Result = 32;
            if (this.Missione == 7 || this.Missione == 8) Result = 42;
        }
        else if (this.Capitolo == 0) Result = 1;
        else Result = 52;

        return Result;
    },
    CircleLight: function () {      //PRESENZA DELLA LUCE BIANCA CIRCOLARE
        let Light = false;
        if (this.Capitolo < 2) Light = false;
        if (this.Capitolo == 2 && this.Missione >= 1) Light = true;
        if (this.Capitolo > 2) Light = true;
        return Light;
    },
    ExtractionEnable: function () { //MODULO DI ESTRAZIONE COMPRABILE
        let Enable = false;
        if (this.Capitolo < 2) Enable = false;
        if (this.Capitolo == 2 && this.Missione >= 2) Enable = true;
        if (this.Capitolo > 2) Enable = true;
        return Enable;
    },
    CalcDeuterium: function () {
        return this.DeuterioTotal / 200;
    },
    CalcTritium: function () {
        return this.TrizioTotal / 200;
    },
    CalcSun: function () {
        return this.SoleTotal / 100;
    },
    RadarEnable: function () { //MODULO DI RADAR COMPRABILE
        let Enable = false;
        if (this.Capitolo < 5) Enable = false;
        if (this.Capitolo == 5 && this.Missione >= 0) Enable = true;
        if (this.Capitolo > 5) Enable = true;
        return Enable;
    },
};

