            /*-------------------------------------MULTIMATERIALE-----------------------------------*/
            //GEOMETRIA 0 - MATERIALE 28 - LUCE VERDE 0x3f782f (BASIC)
            this.Multi[0].Geometry[2].Coaxial[0] = Var.Cupole;               //0 2 - GRUPPO CUPOLE
            this.Multi[0].Geometry[0].Linear[0] = Var.Torus1;               //0 0 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 1
            this.Multi[0].Geometry[1].Linear[0] = Var.Torus2;               //0 1 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 2

            //GEOMETRIA 1 - MATERIALE 26 - INTERNI CITY 1, BASICO, TEXTURE COLORE (BASIC) - MAPPA COLORE, FRONT SIDE
            this.Multi[1].Geometry[2].Coaxial[0] = Var.Cupole;               //1 2 - GRUPPO CUPOLE
            this.Multi[1].Geometry[0].Linear[0] = Var.Torus1;               //1 0 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 1
            this.Multi[1].Geometry[1].Linear[0] = Var.Torus2;               //1 1 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 2

            //GEOMETRIA 2 - MATERIALE 27 - INTERNI CITY 1, BASICO, TEXTURE COLORE (BASIC) - MAPPA COLORE, FRONT SIDE
            this.Multi[2].Geometry[2].Coaxial[0] = Var.Cupole;               //2 2 - GRUPPO CUPOLE
            this.Multi[2].Geometry[0].Linear[0] = Var.Torus1;               //2 0 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 1
            this.Multi[2].Geometry[1].Linear[0] = Var.Torus2;               //2 1 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 2

            //GEOMETRIA 3 - MATERIALE 6 - LUCE ROSSA LAMPEGGIANTE (BASIC)
            this.Multi[3].Geometry[2].Linear[0] = Var.Torus1;               //3 2 - GRUPPO SUPPORTI STRUTTURE TOROIDALI
            this.Multi[3].Geometry[3].Linear[0] = Var.Torus2;               //3 3 - GRUPPO SUPPORTI STRUTTURE TOROIDALI
            this.Multi[3].Geometry[0].Coaxial[0] = Var.Docks;               //3 0 - GRUPPO PARCHEGGI 1
            this.Multi[3].Geometry[1].Coaxial[0] = Var.Docks;               //3 1 - GRUPPO PARCHEGGI 2

            //GEOMETRIA 4 - MATERIALE 5 - LUCE BIANCA LAMPEGGIANTE (BASIC)
            this.Multi[4].Geometry[0].Coaxial[0] = Var.Docks;               //4 0 - GRUPPO PARCHEGGI 1
            this.Multi[4].Geometry[1].Coaxial[0] = Var.Docks;               //4 1 - GRUPPO PARCHEGGI 2

            //GEOMETRIA 5 - MATERIALE 7 - LUCE BIANCA (BASIC)
            this.Multi[5].Geometry[2].Linear[0] = Var.Torus1;               //5 2 - GRUPPO OBLO MOLTIPLICATI LUNGO L'ASSE Z - GRUPPI LATERALI 1 - LIVELLO D
            this.Multi[5].Geometry[3].Linear[0] = Var.Torus2;               //5 3 - GRUPPO OBLO MOLTIPLICATI LUNGO L'ASSE Z - GRUPPI LATERALI 2 - LIVELLO D

            //GEOMETRIA 6 - MATERIALE 3 - VETRO LUCIDO CON RIFLESSO COLORATO (PHONG)
