            this.Multi[6].Geometry[1].Linear[0] = Var.Torus1;               //6 1 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 1
            this.Multi[6].Geometry[2].Linear[0] = Var.Torus2;               //6 2 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 2

            /*-------------------------------------MATERIALE SINGOLO-----------------------------------*/
            //GEOMETRIA 0 - MATERIALE 1 - METALLO LUCIDO RUVIDO VERNICATO CON RIFLESSO COLORATO (PHONG)
            this.Multi[7].Geometry[2].Coaxial[0] = Var.Cupole;               //0 2 - GRUPPO BRACCI CUPOLE
            this.Multi[7].Geometry[4].Linear[0] = Var.Torus1;               //0 4 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 1
            this.Multi[7].Geometry[5].Linear[0] = Var.Torus2;               //0 5 - GRUPPO SUPPORTI STRUTTURE TOROIDALI 2
            this.Multi[7].Geometry[8].Coaxial[0] = Var.Docks;               //0 8 - GRUPPO PARCHEGGI 1
            this.Multi[7].Geometry[9].Coaxial[0] = Var.Docks;               //0 9 - GRUPPO PARCHEGGI 2

            //GEOMETRIA 1 - MATERIALE 0 - METALLO LUCIDO RUVIDO VERNICATO CON RIFLESSO COLORATO (PHONG), FLAT SHADING
            this.Multi[8].Geometry[2].Coaxial[0] = Var.Cupole;               //1 2 - GRUPPO BRACCI CUPOLE
            this.Multi[8].Geometry[0].Linear[0] = Var.Torus1;               //1 0 - GRUPPO SUPPORTI STRUTTURE TOROIDALI
            this.Multi[8].Geometry[1].Linear[0] = Var.Torus2;               //1 1 - GRUPPO SUPPORTI STRUTTURE TOROIDALI
            this.Multi[8].Geometry[3].Coaxial[0] = Var.Docks;               //1 3 - GRUPPO PARCHEGGI 1
            this.Multi[8].Geometry[4].Coaxial[0] = Var.Docks;               //1 4 - GRUPPO PARCHEGGI 2

