function SetHudLoader(Hud) {
    const RandomNozione = Math.floor(Math.random() * 2);     //0 NOZIONE SCIENTIFICA, 1 NOZIONE GIOCO

    if (RandomNozione == 0) {
        let RandomNum = Math.floor(Math.random() * Testi.NozioniScient.length);
        Hud.setImageUrl(0, NPC.Radio.Immagini[4][GlobalVar.GenderNPC]);
        Hud.setButtonText(0, Testi.NozioniScient[RandomNum][GlobalVar.Language]);
    };
    if (RandomNozione > 0) {
        let RandomNum = Math.floor(Math.random() * Testi.NozioniGioco.length);
        Hud.setImageUrl(0, NPC.Guida.Immagini[GlobalVar.GenderNPC]);
        Hud.setButtonText(0, Testi.NozioniGioco[RandomNum][GlobalVar.Language]);
    };

    Hud.render();
};
GameParam.LoaderScreen.FunctHud = SetHudLoader;
