const RandomColors = S0_LoadRandomColors(SaveSystem, GlobalVar.RandomColors);

function AssociaColoreCasualeStazioni() {
    let Colors = 0;       //NUMERO DI COLORI NECESSARI
    for (let i = 0; i < Oggetti.PlanetarySystem.Modular.length; i++) {
        //ASSOCIA IL GRUPPO DI LUNE A UN OGGETTO
        const MoonsGroup = Oggetti.PlanetarySystem.Modular[i].Modular;

        //PER TUTTE LE LUNE NEL GRUPPO
        for (let a = 0; a < MoonsGroup.length; a++) {
            if (MoonsGroup[a].Type == 1) {          //CAMBIA COLORE HUB
                MoonsGroup[a].Color1 = RandomColors[Colors];
                Colors++;
            };
            if (MoonsGroup[a].Type == 2) {          //CAMBIA COLORE CITY
                MoonsGroup[a].Color1 = RandomColors[Colors];
                Colors++;
            };
            if (MoonsGroup[a].Type == 3) {          //CAMBIA COLORE INDUSTRIAL
                MoonsGroup[a].Color2 = RandomColors[Colors];
                Colors++;
            };
            if (MoonsGroup[a].Type == 4) {          //CAMBIA COLORE HANGAR
                MoonsGroup[a].Color1 = RandomColors[Colors];
                Colors++;
            };
            if (MoonsGroup[a].Type == 5) {          //CAMBIA COLORE RESEARCH
                MoonsGroup[a].Color1 = RandomColors[Colors];
                Colors++;
            };
            if (MoonsGroup[a].Type == 6) {          //CAMBIA COLORE TELESCOPIO
                MoonsGroup[a].Color1 = RandomColors[Colors];
                Colors++;
            };
            if (MoonsGroup[a].Type == 7) {          //CAMBIA COLORE CONTAINER
                MoonsGroup[a].Color1 = RandomColors[Colors];
                Colors++;
            };
            //SE LA LUNA HA DELLE SUBLUNE
            if (MoonsGroup[a].Modular.length > 0)
                //PER TUTTE LE SUB-LUNE
                for (let b = 0; b < MoonsGroup[a].Modular.length; b++) {
                    if (MoonsGroup[a].Modular[b].Type == 1) {           //CAMBIA COLORE HUB
                        MoonsGroup[a].Modular[b].Color1 = RandomColors[Colors];
                        Colors++;
                    };
                    if (MoonsGroup[a].Modular[b].Type == 2) {           //CAMBIA COLORE CITY
                        MoonsGroup[a].Modular[b].Color1 = RandomColors[Colors];
                        Colors++;
                    };
                    if (MoonsGroup[a].Modular[b].Type == 3) {           //CAMBIA COLORE INDUSTRIAL
                        MoonsGroup[a].Modular[b].Color2 = RandomColors[Colors];
                        Colors++;
                    };
                    if (MoonsGroup[a].Modular[b].Type == 4) {           //CAMBIA COLORE HANGAR
                        MoonsGroup[a].Modular[b].Color1 = RandomColors[Colors];
                        Colors++;
                    };
                    if (MoonsGroup[a].Modular[b].Type == 5) {           //CAMBIA COLORE RESEARCH
                        MoonsGroup[a].Modular[b].Color1 = RandomColors[Colors];
                        Colors++;
                    };
                    if (MoonsGroup[a].Modular[b].Type == 6) {           //CAMBIA COLORE TELESCOPIO
                        MoonsGroup[a].Modular[b].Color1 = RandomColors[Colors];
                        Colors++;
                    };
                    if (MoonsGroup[a].Modular[b].Type == 7) {           //CAMBIA COLORE CONTAINER
                        MoonsGroup[a].Modular[b].Color1 = RandomColors[Colors];
                        Colors++;
                    };
                };
        };
    };
    //console.log(Colors);
};
AssociaColoreCasualeStazioni();

